import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface Variant {
  name: string;
  conversionRate: number;
  confidenceLevel: number;
  lift: number;
}

interface ABTestResults {
  testName: string;
  variants: Variant[];
  overallLift: number;
}

export default function Widget() {
  const abTestResults = response.data as ABTestResults;
  const { testName, variants, overallLift } = abTestResults;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#0284C7' }}>
              {testName}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Overall Lift: {overallLift}%
            </Typography>
          </Box>

          <Stack spacing={1}>
            {variants.map((variant) => {
              const isPositive = variant.lift >= 0;
              return (
                <Box key={variant.name}>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Typography variant="body2" sx={{ fontWeight: 500, color: '#1F2937' }}>
                      {variant.name}
                    </Typography>
                    <Chip
                      label={`${variant.lift}%`}
                      color={isPositive ? 'primary' : 'secondary'}
                      icon={isPositive ? <TrendingUp /> : <TrendingDown />}
                      sx={{ fontSize: 12, height: 24 }}
                    />
                  </Stack>
                  <Typography variant="caption" color="text.secondary">
                    Conversion Rate: {variant.conversionRate}%, Confidence Level: {variant.confidenceLevel}%
                  </Typography>
                </Box>
              );
            })}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
